"use client";

import React, { useState, useEffect, useRef } from "react";

export const WebGLShaderBackground = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isLibLoaded, setIsLibLoaded] = useState(false);

  useEffect(() => {
    if (window.THREE) {
      setIsLibLoaded(true);
      return;
    }
    const script = document.createElement("script");
    script.src = "https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js";
    script.async = true;
    script.onload = () => setIsLibLoaded(true);
    document.body.appendChild(script);
    return () => {
      if (script.parentNode) document.body.removeChild(script);
    };
  }, []);

  useEffect(() => {
    if (!isLibLoaded || !canvasRef.current) return;

    const THREE = window.THREE;
    const canvas = canvasRef.current;
    let scene, camera, renderer, mesh, uniforms, animationId;

    const vertexShader = `
      void main() {
        gl_Position = vec4(position, 1.0);
      }
    `;

    const fragmentShader = `
      precision highp float;
      uniform vec2 resolution;
      uniform float time;
      uniform vec2 mouse;

      float random (in vec2 st) {
          return fract(sin(dot(st.xy, vec2(12.9898,78.233))) * 43758.5453123);
      }

      void main() {
        vec2 uv = (gl_FragCoord.xy * 2.0 - resolution.xy) / min(resolution.x, resolution.y);
        vec2 mouse_uv = (mouse * 2.0 - 1.0);
        mouse_uv.y *= -1.0;

        float t = time * 0.2;
        float dist = length(uv - mouse_uv);
        float angle = atan(uv.y - mouse_uv.y, uv.x - mouse_uv.x);
        float swirl = 1.0 / (dist * 20.0 + 1.0);
        angle += swirl * t * 2.0;

        float arms = sin(angle * 5.0 - t * 2.0) * 0.5 + 0.5;
        arms = smoothstep(0.7, 1.0, arms);
        float white_hole = smoothstep(0.1, 0.0, dist);
        float color_intensity = (arms + white_hole) * smoothstep(1.5, 0.2, dist);
        float stars = step(0.998, random(uv + t * 0.01));
        vec3 color = vec3(color_intensity + stars);

        gl_FragColor = vec4(color, 1.0);
      }
    `;

    const initScene = () => {
      scene = new THREE.Scene();
      renderer = new THREE.WebGLRenderer({ canvas });
      renderer.setPixelRatio(window.devicePixelRatio);
      renderer.setClearColor(new THREE.Color(0x000000));
      camera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);

      uniforms = {
        resolution: { value: [window.innerWidth, window.innerHeight] },
        time: { value: 0.0 },
        mouse: { value: [0.5, 0.5] },
      };

      const geometry = new THREE.PlaneGeometry(2, 2);
      const material = new THREE.ShaderMaterial({
        vertexShader,
        fragmentShader,
        uniforms,
      });

      mesh = new THREE.Mesh(geometry, material);
      scene.add(mesh);
      handleResize();
    };

    const animate = () => {
      if (uniforms) uniforms.time.value += 0.015;
      if (renderer && scene && camera) {
        renderer.render(scene, camera);
      }
      animationId = requestAnimationFrame(animate);
    };

    const handleResize = () => {
      if (!renderer || !uniforms) return;
      const width = window.innerWidth;
      const height = window.innerHeight;
      renderer.setSize(width, height, false);
      uniforms.resolution.value = [width, height];
    };

    const handleMouseMove = (event: MouseEvent) => {
      if (uniforms) {
        uniforms.mouse.value = [event.clientX / window.innerWidth, event.clientY / window.innerHeight];
      }
    };

    initScene();
    animate();
    window.addEventListener("resize", handleResize);
    window.addEventListener("mousemove", handleMouseMove);

    return () => {
      if (animationId) cancelAnimationFrame(animationId);
      window.removeEventListener("resize", handleResize);
      window.removeEventListener("mousemove", handleMouseMove);
      if (mesh) {
        scene?.remove(mesh);
        mesh.geometry.dispose();
        if (mesh.material) mesh.material.dispose();
      }
      renderer?.dispose();
    };
  }, [isLibLoaded]);

  return <canvas ref={canvasRef} id="scene-container" className="fixed top-0 left-0 w-full h-full z-0" />;
};
